// Cross-language byte-compatibility tests.
//
// The expected values are generated by the Rust side:
//   cargo run -p veilux-sdk --example vectors
// If the kernel's signing format ever changes, regenerate and update here.

import { test } from "node:test";
import assert from "node:assert/strict";
import {
  PartyIdentity,
  builders,
  signingBytes,
  toHex,
  tokenId as deriveTokenId,
} from "../dist/index.js";

const ALICE_SEED = new Uint8Array(32).fill(1);
const ALICE_PUBKEY = "8a88e3dd7409f195fd52db2d3cba5d72ca6709bf1d94121bf3748801b40f6f5c";
const TOKEN_ID = "0xfebdbcd19fcfe4e3d1fd12fdaa4706c6652843da5885897eb0d935477fc4f034";

const CREATE = {
  signing_bytes:
    "",
  command_id: "0x844cfe081c7204b41d56b68a37a1a888eb7e243685c3b0eca43c3fb4f2569af3",
  signature:
    "63aa86214e1a6d0a796f4d67ddac81bb2fba8423db937a6162ec055cf6ddeb41ce26f759bece9ba8092836a06e33db24cb5eea179810b23d99248fc412315b01",
};

const TRANSFER = {
  signing_bytes:
    "",
  command_id: "0x250337cfb424c01eb800f8d3823168b7226ae191314aaf8b54fa9a4ca47a4b81",
  signature:
    "55ef92b2ad7d9068c4a8e5144bf5ae6fb1dde0df6ebaef50dc17414ade00df65eaffcdca93e0d80236aefa9fa384ab3ba96cbe15b1f26019430646adf26c370e",
};

function bytesToHex(b: number[]): string {
  return b.map((x) => x.toString(16).padStart(2, "0")).join("");
}

test("public key derivation matches Rust", () => {
  const alice = PartyIdentity.fromSeed("alice", ALICE_SEED);
  assert.equal(bytesToHex(Array.from(alice.publicKey())), ALICE_PUBKEY);
});

test("token id derivation matches Rust", () => {
  assert.equal(deriveTokenId("alice", "GLD", "Gold Coin"), TOKEN_ID);
});

test("token_create: signing bytes, id, and signature match Rust", () => {
  const alice = PartyIdentity.fromSeed("alice", ALICE_SEED);
  const cmd = builders.tokenCreate("alice", "Public", 0, "Gold Coin", "GLD", 18, 1_000_000n, true);

  assert.equal(toHex(signingBytes(cmd)).slice(2), CREATE.signing_bytes);

  const signed = alice.sign(cmd);
  assert.equal(bytesToHex(signed.signature), CREATE.signature);
});

test("token_transfer (private): signing bytes and signature match Rust", () => {
  const alice = PartyIdentity.fromSeed("alice", ALICE_SEED);
  const cmd = builders.tokenTransfer(
    "alice",
    { Parties: ["alice", "bob"] },
    1,
    TOKEN_ID,
    "bob",
    250_000n,
  );

  assert.equal(toHex(signingBytes(cmd)).slice(2), TRANSFER.signing_bytes);

  const signed = alice.sign(cmd);
  assert.equal(bytesToHex(signed.signature), TRANSFER.signature);
});
